    local type="$1"
    case "$type" in
        today|tomorrow|morning|afternoon)
            echo "2"
            ;;
        3days)
            echo "4"
            ;;
        7days)
            echo "8"
            ;;
        *)
            echo "2"
            ;;
    esac
