get_target_date() {
    local type="$1"
    local offset=0

    case "$type" in
        today|morning|afternoon)
            offset=0
            ;;
        tomorrow)
            offset=1
            ;;
        3days)
            offset=2
            ;;
        7days)
            offset=6
            ;;
    esac

    date -d "+${offset} days" '+%Y-%m-%d'
}

# Get end date for filtering (for multi-day forecasts)
get_end_date() {
    local type="$1"
    case "$type" in
        today|tomorrow|morning|afternoon)
            get_target_date "$type"
            ;;
        3days|7days)
            get_target_date "$type"
            ;;
        *)
            date '+%Y-%m-%d'
            ;;
    esac
}

