/**
 * Telegram Weather Forwarder
 *
 * This API route forwards Telegram updates to the weather trigger handler.
 * It should be configured as the Telegram webhook URL to handle weather commands.
 *
 * Usage:
 *   POST /api/telegram/weather
 *
 * Expected body: Telegram Update object (JSON)
 */

import { NextResponse } from 'next/server';
import { exec } from 'child_process';
import { promisify } from 'util';

const execAsync = promisify(exec);

export async function POST(request) {
  try {
    // Parse the Telegram update
    const update = await request.json();

    // Log the update for debugging
    console.log('Telegram update received:', JSON.stringify(update, null, 2));

    // Check if it contains a message or callback query
    const hasMessage = update.message && update.message.text;
    const hasCallbackQuery = update.callback_query;

    // Check if it's a weather command
    let isWeatherCommand = false;
    if (hasMessage) {
      const text = update.message.text.trim().toLowerCase();
      isWeatherCommand = text === '/tempo' || text === 'previsГЈo';
    }

    // Always forward updates to the weather handler
    // The handler will decide whether to respond or not
    const updateJson = JSON.stringify(update);

    try {
      // Run the weather handler
      const { stdout, stderr } = await execAsync(
        `node /job/triggers/handle-telegram-weather.js '${updateJson}'`,
        {
          env: {
            ...process.env,
            TELEGRAM_BOT_TOKEN: process.env.TELEGRAM_BOT_TOKEN,
            TELEGRAM_CHAT_ID: process.env.TELEGRAM_CHAT_ID
          },
          timeout: 30000 // 30 second timeout
        }
      );

      console.log('Weather handler output:', stdout);
      if (stderr) {
        console.error('Weather handler stderr:', stderr);
      }
    } catch (error) {
      console.error('Error running weather handler:', error.message);
      // Don't fail the request - the handler might have already responded
